import type {
  CanvasNodeConnectionEvent,
  CanvasNodeConnectionSide,
  CanvasNodeInteractionState,
  CanvasNodeStatus,
} from "@workspace/ui/components/canvas-node/canvas-node";
import type { ReactNode } from "react";

export interface EntryNodeStates {
  name: string;
}

export interface EntryNodeAccessDomain {
  label?: string;
  value: string;
}

export interface EntryNodeTarget {
  id?: string;
  label: string;
  status?: CanvasNodeStatus;
  value: string;
}

export type EntryNodeTargetKey = string;

export type EntryNodeCopyTargetHandler = (
  target: EntryNodeTarget,
  index: number
) => Promise<void> | void;

export type EntryNodeOpenTargetSettingsHandler = (
  target: EntryNodeTarget,
  index: number
) => void;

export type EntryNodeStartConnectionHandler = (
  side: CanvasNodeConnectionSide,
  event: CanvasNodeConnectionEvent
) => void;

export interface EntryNodeState {
  accessDomain?: EntryNodeAccessDomain;
  copiedTargetKey?: EntryNodeTargetKey | null;
  states: EntryNodeStates;
  targets?: EntryNodeTarget[];
}

export interface EntryNodeActions {
  copyTarget: EntryNodeCopyTargetHandler;
  openTargetSettings?: EntryNodeOpenTargetSettingsHandler;
}

export interface EntryNodeMeta {
  copiedFeedbackMs?: number;
}

export interface EntryNodeContextValue {
  actions: EntryNodeActions;
  meta: EntryNodeMeta;
  state: EntryNodeState;
}

export interface EntryNodeProviderProps {
  children?: ReactNode;
  value: EntryNodeContextValue;
}

export interface EntryNodeRootProps {
  accessDomain?: EntryNodeAccessDomain;
  children?: ReactNode;
  copiedFeedbackMs?: number;
  copiedTargetKey?: EntryNodeTargetKey | null;
  defaultExpanded?: boolean;
  expanded?: boolean;
  interaction?: CanvasNodeInteractionState;
  onCopyTarget?: EntryNodeCopyTargetHandler;
  onExpandedChange?: (expanded: boolean) => void;
  onOpenTargetSettings?: EntryNodeOpenTargetSettingsHandler;
  onStartConnection?: EntryNodeStartConnectionHandler;
  states: EntryNodeStates;
  targets?: EntryNodeTarget[];
}

"use client";

import { createContext, use } from "react";

import type { EntryNodeContextValue } from "./entry-node.types";

export const EntryNodeContext = createContext<EntryNodeContextValue | null>(
  null
);

export function useEntryNode(): EntryNodeContextValue {
  const value = use(EntryNodeContext);

  if (!value) {
    throw new Error(
      "EntryNode: compound components must be used within EntryNode.Root"
    );
  }

  return value;
}

"use client";

import { EntryNodeContext } from "./entry-node.context";
import type { EntryNodeProviderProps } from "./entry-node.types";

export function EntryNodeProvider({ children, value }: EntryNodeProviderProps) {
  return <EntryNodeContext value={value}>{children}</EntryNodeContext>;
}

"use client";

import { CanvasNodeRoot } from "@workspace/ui/components/canvas-node/canvas-node.root";
import { useCallback, useEffect, useMemo, useRef, useState } from "react";

import { EntryNodeProvider } from "./entry-node.provider";
import type {
  EntryNodeContextValue,
  EntryNodeRootProps,
  EntryNodeTarget,
  EntryNodeTargetKey,
} from "./entry-node.types";

const DEFAULT_COPIED_FEEDBACK_MS = 1200;

async function copyTextToClipboard(value: string) {
  if (typeof navigator === "undefined" || !navigator.clipboard) {
    return;
  }

  await navigator.clipboard.writeText(value);
}

export function EntryNodeRoot({
  accessDomain,
  children,
  copiedFeedbackMs = DEFAULT_COPIED_FEEDBACK_MS,
  copiedTargetKey,
  defaultExpanded,
  expanded,
  interaction,
  onCopyTarget,
  onExpandedChange,
  onOpenTargetSettings,
  onStartConnection,
  states,
  targets,
}: EntryNodeRootProps) {
  const [internalCopiedTargetKey, setInternalCopiedTargetKey] =
    useState<EntryNodeTargetKey | null>(null);
  const resetTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const copiedTargetControlled = copiedTargetKey !== undefined;

  useEffect(
    () => () => {
      if (resetTimerRef.current) {
        clearTimeout(resetTimerRef.current);
      }
    },
    []
  );

  const copyTarget = useCallback(
    async (target: EntryNodeTarget, index: number) => {
      if (!target.value) {
        return;
      }

      if (onCopyTarget) {
        await onCopyTarget(target, index);
      } else {
        await copyTextToClipboard(target.value);
      }

      if (!copiedTargetControlled) {
        setInternalCopiedTargetKey(target.id ?? String(index));

        if (resetTimerRef.current) {
          clearTimeout(resetTimerRef.current);
        }

        resetTimerRef.current = setTimeout(() => {
          setInternalCopiedTargetKey(null);
          resetTimerRef.current = null;
        }, copiedFeedbackMs);
      }
    },
    [copiedFeedbackMs, copiedTargetControlled, onCopyTarget]
  );

  const value = useMemo(
    (): EntryNodeContextValue => ({
      actions: {
        copyTarget,
        openTargetSettings: onOpenTargetSettings,
      },
      meta: {
        copiedFeedbackMs,
      },
      state: {
        accessDomain,
        copiedTargetKey: copiedTargetControlled
          ? copiedTargetKey
          : internalCopiedTargetKey,
        states,
        targets,
      },
    }),
    [
      copiedFeedbackMs,
      copiedTargetControlled,
      copiedTargetKey,
      copyTarget,
      accessDomain,
      internalCopiedTargetKey,
      onOpenTargetSettings,
      states,
      targets,
    ]
  );

  return (
    <CanvasNodeRoot
      defaultExpanded={defaultExpanded}
      expanded={expanded}
      interaction={interaction}
      onExpandedChange={onExpandedChange}
      onStartConnection={onStartConnection}
    >
      <EntryNodeProvider value={value}>{children}</EntryNodeProvider>
    </CanvasNodeRoot>
  );
}

"use client";

import { CanvasNode } from "@workspace/ui/components/canvas-node/canvas-node";
import { cn } from "@workspace/ui/lib/utils";
import { Router } from "lucide-react";

import { useEntryNode } from "./entry-node.context";
import { resolveEntryNodeTargetStatus } from "./entry-node.status";
import { EntryNodeTargetList } from "./entry-node.target";
import type { EntryNodeAccessDomain } from "./entry-node.types";

function getAccessDomain(
  fallbackName: string,
  accessDomain: EntryNodeAccessDomain | undefined
) {
  return (
    accessDomain ?? {
      label: "Access domain",
      value: fallbackName,
    }
  );
}

function useEntryNodeAccessDomain() {
  const {
    state: { accessDomain, states },
  } = useEntryNode();

  return getAccessDomain(states.name, accessDomain);
}

function useEntryNodeResolvedStatus() {
  const {
    state: { targets },
  } = useEntryNode();

  return resolveEntryNodeTargetStatus(targets);
}

export function EntryNodeContent() {
  return (
    <CanvasNode.Frame>
      <CanvasNode.ConnectionLayer />
      <CanvasNode.DragStateFrame>
        <CanvasNode.Surface>
          <CanvasNode.Header>
            <EntryNodeHeaderContent />
          </CanvasNode.Header>
          <CanvasNode.Body>
            <EntryNodeTargetList />
          </CanvasNode.Body>
        </CanvasNode.Surface>
      </CanvasNode.DragStateFrame>
      <CanvasNode.ExpandButton />
    </CanvasNode.Frame>
  );
}

export function EntryNodeHeaderContent({ className }: { className?: string }) {
  return (
    <div className={cn("canvas-node-header-content min-w-0 flex-1", className)}>
      <div className="flex min-w-0 items-center justify-between gap-1.5">
        <EntryNodeAccess />
        <EntryNodeStatus />
      </div>
    </div>
  );
}

export function EntryNodeAccess({ className }: { className?: string }) {
  const accessDomain = useEntryNodeAccessDomain();
  const Icon = Router;

  return (
    <span className={cn("flex min-w-0 flex-1 items-center gap-1.5", className)}>
      <span className="flex size-9 shrink-0 items-center justify-center rounded-lg bg-white/5">
        <Icon aria-hidden className="size-4 text-zinc-50" />
      </span>
      <span className="flex min-w-0 flex-1 flex-col gap-1.5">
        <span
          className="min-w-0 truncate font-normal text-sm text-zinc-50 leading-5"
          title={accessDomain.value}
        >
          {accessDomain.value}
        </span>
        <span className="min-w-0 truncate font-normal text-muted-foreground text-xs leading-4">
          {accessDomain.label ?? "Access domain"}
        </span>
      </span>
    </span>
  );
}

export function EntryNodeStatus({ className }: { className?: string }) {
  const status = useEntryNodeResolvedStatus();

  return <CanvasNode.Status className={className} status={status} />;
}

import type {
  CanvasNodeStatus,
  CanvasNodeStatusTone,
} from "@workspace/ui/components/canvas-node/canvas-node";
import { normalizeCanvasNodeStatus } from "@workspace/ui/components/canvas-node/canvas-node.status";

import type { EntryNodeTarget } from "./entry-node.types";

const ACCESSIBLE_TONES = new Set<CanvasNodeStatusTone>([
  "accessible",
  "available",
  "bound",
  "complete",
  "ready",
  "running",
  "succeeded",
]);

const PROGRESSING_TONES = new Set<CanvasNodeStatusTone>([
  "binding",
  "creating",
  "pending",
  "progressing",
]);

const FAILED_TONES = new Set<CanvasNodeStatusTone>([
  "error",
  "failed",
  "inaccessible",
  "unhealthy",
]);

function resolveTargetTone(status: CanvasNodeStatus | undefined) {
  return status?.tone ?? normalizeCanvasNodeStatus(status?.label);
}

function everyTone(
  tones: CanvasNodeStatusTone[],
  bucket: Set<CanvasNodeStatusTone>
) {
  return tones.every((tone) => bucket.has(tone));
}

export function resolveEntryNodeTargetStatus(
  targets: readonly EntryNodeTarget[] | undefined
): CanvasNodeStatus {
  if (!targets || targets.length === 0) {
    return { label: "Not configured", tone: "unknown" };
  }

  const tones = targets.map((target) => resolveTargetTone(target.status));

  if (everyTone(tones, ACCESSIBLE_TONES)) {
    return { label: "Accessible", tone: "accessible" };
  }

  if (everyTone(tones, PROGRESSING_TONES)) {
    return { label: "Progressing", tone: "progressing" };
  }

  if (everyTone(tones, FAILED_TONES)) {
    return { label: "Inaccessible", tone: "inaccessible" };
  }

  if (tones.every((tone) => tone === "unknown")) {
    return { label: "Not configured", tone: "unknown" };
  }

  return { label: "Degraded", tone: "degraded" };
}

"use client";

import { Button } from "@workspace/ui/components/button";
import { CanvasNode } from "@workspace/ui/components/canvas-node/canvas-node";
import { cn } from "@workspace/ui/lib/utils";
import { Check, Copy, Ellipsis } from "lucide-react";
import type { SyntheticEvent } from "react";

import { useEntryNode } from "./entry-node.context";
import type { EntryNodeTarget } from "./entry-node.types";

function stopNodeControlEvent(event: SyntheticEvent) {
  event.stopPropagation();
}

function getTargetKey(target: EntryNodeTarget, index: number) {
  return target.id ?? String(index);
}

export function EntryNodeTargetList({ className }: { className?: string }) {
  const {
    state: { targets = [] },
  } = useEntryNode();
  const scrollable = targets.length > 2;

  if (targets.length === 0) {
    return (
      <div
        className={cn(
          "entry-node-target-empty mt-2.5 flex min-w-0 items-center rounded-lg bg-zinc-950/20 px-2.5 text-muted-foreground text-xs leading-4",
          className
        )}
        data-slot="entry-node-target-empty"
      >
        Not configured
      </div>
    );
  }

  return (
    <div
      className={cn(
        "entry-node-target-list mt-2.5 flex min-w-0 flex-col gap-2",
        className
      )}
      data-scrollable={scrollable || undefined}
      data-slot="entry-node-target-list"
    >
      {targets.map((target, index) => (
        <EntryNodeTargetRow
          index={index}
          key={getTargetKey(target, index)}
          target={target}
        />
      ))}
    </div>
  );
}

export function EntryNodeTargetRow({
  className,
  index,
  target,
}: {
  className?: string;
  index: number;
  target: EntryNodeTarget;
}) {
  const {
    actions,
    state: { copiedTargetKey },
  } = useEntryNode();
  const copied = copiedTargetKey === getTargetKey(target, index);

  return (
    <section
      className={cn(
        "group/target entry-node-target-row flex min-w-0 items-start gap-2 rounded-lg bg-zinc-950/20 p-2.5 transition-colors hover:bg-zinc-950/30",
        className
      )}
      data-slot="entry-node-target-row"
    >
      <div className="flex min-w-0 flex-1 flex-col gap-2">
        <div className="flex min-w-0 items-center gap-1.5">
          <CanvasNode.StatusDot size="small" status={target.status} />
          <span className="min-w-0 truncate font-normal text-muted-foreground text-xs leading-4">
            {target.label}
          </span>
        </div>
        <Button
          className="group/copy flex h-7 w-full min-w-0 items-center justify-between gap-2 rounded-md border-0 bg-transparent px-0 py-1.5 text-left font-normal text-xs text-zinc-50 leading-4 shadow-none transition-colors hover:bg-transparent hover:text-zinc-50 focus-visible:bg-white/5 data-[copied=true]:bg-transparent"
          data-copied={copied ? "true" : undefined}
          data-slot="entry-node-target-copy"
          onClick={(event) => {
            event.stopPropagation();
            Promise.resolve(actions.copyTarget(target, index)).catch(
              () => undefined
            );
          }}
          onDoubleClick={stopNodeControlEvent}
          onPointerDown={stopNodeControlEvent}
          size={null}
          title={target.value}
          type="button"
          variant={null}
        >
          <span className="min-w-0 truncate">{target.value}</span>
          {copied ? (
            <Check aria-hidden className="size-4 shrink-0" />
          ) : (
            <Copy
              aria-hidden
              className="size-4 shrink-0 opacity-0 transition-opacity group-hover/target:opacity-100 group-focus-visible/copy:opacity-100"
            />
          )}
        </Button>
      </div>
      <Button
        aria-label={`Open settings for ${target.label}`}
        className="nodrag nopan flex size-8 shrink-0 items-center justify-center rounded-lg border-0 bg-zinc-950/20 p-0 text-zinc-50 shadow-none transition-colors hover:bg-zinc-950/30 hover:text-zinc-50 focus-visible:bg-zinc-950/30"
        data-slot="entry-node-target-settings"
        onClick={(event) => {
          event.stopPropagation();
          actions.openTargetSettings?.(target, index);
        }}
        onDoubleClick={stopNodeControlEvent}
        onPointerDown={stopNodeControlEvent}
        size={null}
        title={`Open settings for ${target.label}`}
        type="button"
        variant={null}
      >
        <Ellipsis aria-hidden className="size-4" />
      </Button>
    </section>
  );
}

.entry-node-target-list {
  max-height: calc((var(--spacing) * 18 * 2) + (var(--spacing) * 2));
  overflow-y: auto;
  scrollbar-width: none;
}

.entry-node-target-list::-webkit-scrollbar {
  display: none;
}

.entry-node-target-list:not([data-scrollable]) {
  overflow: hidden;
}

.entry-node-target-row,
.entry-node-target-empty {
  min-height: calc(var(--spacing) * 18);
}

// biome-ignore lint/performance/noBarrelFile: entry-node public package surface
export {
  EntryNode,
  resolveEntryNodeTargetStatus,
  useEntryNode,
} from "./entry-node";
export type {
  EntryNodeAccessDomain,
  EntryNodeActions,
  EntryNodeContextValue,
  EntryNodeCopyTargetHandler,
  EntryNodeMeta,
  EntryNodeOpenTargetSettingsHandler,
  EntryNodeProviderProps,
  EntryNodeRootProps,
  EntryNodeStartConnectionHandler,
  EntryNodeState,
  EntryNodeStates,
  EntryNodeTarget,
  EntryNodeTargetKey,
} from "./entry-node.types";

"use client";

import "./entry-node.css";

import {
  EntryNodeAccess,
  EntryNodeContent,
  EntryNodeHeaderContent,
  EntryNodeStatus,
} from "./entry-node.content";
import { EntryNodeRoot } from "./entry-node.root";
import { EntryNodeTargetList, EntryNodeTargetRow } from "./entry-node.target";

// biome-ignore lint/performance/noBarrelFile: compound hook re-export for `import { useEntryNode }`
export { useEntryNode } from "./entry-node.context";
export { resolveEntryNodeTargetStatus } from "./entry-node.status";
export type {
  EntryNodeAccessDomain,
  EntryNodeActions,
  EntryNodeContextValue,
  EntryNodeCopyTargetHandler,
  EntryNodeMeta,
  EntryNodeOpenTargetSettingsHandler,
  EntryNodeProviderProps,
  EntryNodeRootProps,
  EntryNodeStartConnectionHandler,
  EntryNodeState,
  EntryNodeStates,
  EntryNodeTarget,
  EntryNodeTargetKey,
} from "./entry-node.types";

export const EntryNode = {
  Access: EntryNodeAccess,
  Content: EntryNodeContent,
  HeaderContent: EntryNodeHeaderContent,
  Root: EntryNodeRoot,
  Status: EntryNodeStatus,
  TargetList: EntryNodeTargetList,
  TargetRow: EntryNodeTargetRow,
} as const;

const dn = (component: object, name: string) => {
  (component as { displayName?: string }).displayName = name;
};

dn(EntryNodeRoot, "EntryNode.Root");
dn(EntryNodeContent, "EntryNode.Content");
dn(EntryNodeHeaderContent, "EntryNode.HeaderContent");
dn(EntryNodeAccess, "EntryNode.Access");
dn(EntryNodeStatus, "EntryNode.Status");
dn(EntryNodeTargetList, "EntryNode.TargetList");
dn(EntryNodeTargetRow, "EntryNode.TargetRow");
